var jobs=Array.isArray(raw)?raw:(raw.tasks||raw.jobs||[]);
var fixes=0;

function cleanGLM(obj) {
  if(!obj||typeof obj!=="object") return obj;
  if(Array.isArray(obj)) return obj.map(cleanGLM);
  var result={};
